ch := make(chan string)

go func() {
    ch <- "안녕, 채널!" // 송신
}()

msg := <-ch // 수신 (블로킹 대기)
fmt.Println(msg)

// 여러 값 전달
nums := make(chan int)
go func() {
    nums <- 1
    nums <- 2
    nums <- 3
}()
fmt.Println(<-nums, <-nums, <-nums)

// 송신 전용: chan<- int
func producer(ch chan<- int) {
    for i := 0; i < 5; i++ {
        ch <- i
    }
    close(ch)
}
// 수신 전용: <-chan int
func consumer(ch <-chan int) {
    for v := range ch {
        fmt.Println(v)
    }
}
func main() {
    ch := make(chan int)
    go producer(ch)
    consumer(ch) // 0,1,2,3,4
}

ch := make(chan int)

go func() {
    for i := 1; i <= 5; i++ {
        ch <- i
    }
    close(ch) // 더 이상 안 보냄!
}()

// range: 채널 닫힐 때까지 수신
for v := range ch {
    fmt.Println(v) // 1, 2, 3, 4, 5
}

// 닫힌 채널 확인
v, ok := <-ch
fmt.Println(v, ok) // 0 false

func worker(id int, jobs <-chan int,
    results chan<- int) {
    for j := range jobs {
        fmt.Printf("워커%d: 작업%d\n", id, j)
        results <- j * 2
    }
}
func main() {
    jobs := make(chan int, 100)
    results := make(chan int, 100)
    for w := 1; w <= 3; w++ {
        go worker(w, jobs, results)
    }
    for j := 1; j <= 9; j++ { jobs <- j }
    close(jobs)
    for i := 0; i < 9; i++ {
        fmt.Println(<-results)
    }
}
